from pydantic import BaseModel, Field
import requests
import json


class Pipe:
    class Valves(BaseModel):
        WEBHOOK_URL: str = Field(
            default="http://n8n:5678/webhook/ip-lookup", description="N8N webhook URL"
        )

    def __init__(self):
        self.valves = self.Valves()
        self.name = "N8N Webhook"

    async def pipe(self, body: dict) -> str:
        # Extract the user's message from the body
        messages = body.get("messages", [])
        if not messages:
            return "No message provided"

        # Get the last user message
        user_message = messages[-1].get("content", "")

        try:
            # Try to parse message as JSON, otherwise send as plain text in a body field
            try:
                message_json = json.loads(user_message)
            except json.JSONDecodeError:
                message_json = {"body": user_message}

            # Send to N8N webhook
            response = requests.post(
                self.valves.WEBHOOK_URL,
                json=message_json,
                headers={"Content-Type": "application/json"},
                timeout=10,
            )

            if response.status_code == 200:
                # Return raw response as formatted JSON
                return json.dumps(response.json(), indent=2)
            else:
                return f"Error: Webhook returned status code {response.status_code}\n{response.text}"

        except requests.exceptions.Timeout:
            return "Error: Request to N8N webhook timed out"
        except requests.exceptions.ConnectionError:
            return "Error: Could not connect to N8N webhook. Make sure N8N is running."
        except Exception as e:
            return f"Error: {str(e)}"
